var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 공업 지구\\n이터니움 보관소 <color=#ffd34c>CSE</color> LV.3.7","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>工業地区\\nエタニウム保管所 - <color=#ffd34c>CSE</color> Lv.3.7","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>, Industrial District\\nEternium Storeroom <color=#ffd34c>CSE</color> Lv.3.7","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>工業區\\n永恆之金保管所<color=#ffd34c>CSE</color> LV.3.7"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"말도 안 돼……!","JPN":"いやおかしいでしょ……！","ENG":"This is insane...!","TWN":"怎麼可能……！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"계측기가 가리키는 CSE레벨 지표가 분 단위로 치솟고 있잖아?","JPN":"計測器のCSEレベル指標、うなぎ登りなんだけど！","ENG":"The CSE level on the monitors is skyrocketing by the minute!","TWN":"儀器顯示的CSE等級指標，每分鐘都在飆升耶？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이렇게 예쁜 그래프는 주식판에서도 본 적 없다고!","JPN":"ここまで綺麗な右肩上がりのグラフ、株価チャートでも見たことないし！","ENG":"I've never seen such a beautiful graph, not even in the stock market!","TWN":"就連股市都沒看過這麼漂亮的曲線！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"조심해요, 불량식품.","JPN":"気をつけてください、お菓子さん。","ENG":"Be careful, junk food.","TWN":"小心點，垃圾食物。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"불과 몇 시간 전까지 이곳에 사람이 있었다는 게 믿어지지 않을 지경이에요.","JPN":"数時間前までここに人がいたとは思えないほどひどい状態です。","ENG":"It's hard to believe people were still working here just a few hours ago.","TWN":"我好難相信這裡在幾個小時前還有人存在。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무리 대균열 영향권이라고 해도, 이렇게까지 침식이 빠르다니…….","JPN":"いくら大亀裂の影響圏内とはいえ、こんなに侵食が速いだなんて……","ENG":"Even accounting for the Grand Dimension Crevice's influence, the rate of Corruption is far too fast...","TWN":"就算是在大峽谷影響範圍內，侵蝕速度也未免太快了……"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"망할 리하르트! 쓸데없이 성실해가지곤……!","JPN":"リヒャルトのやつ……！　無駄に真面目なんだから……！","ENG":"Damn you, Richard! Being diligent at the worst possible times...!","TWN":"該死的理查！偏偏在這種地方認真……！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"왜 이터니움 보관소를 지구마다 지어서 이 개고생을 시키는 거야?","JPN":"なんでエタニウム保管所を地区ごとに建てたのよ！　おかげで集めるのに苦労するじゃない！","ENG":"Why did he have to build an Eternium storeroom in every district and make us go through this hell?","TWN":"為什麼要在每個區域都建一座永恆之金保管所，害我們這麼辛苦？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"게다가 보관소 보안 레벨은 왜 또 최고로 설정해 놓은 건데?","JPN":"保管所のセキュリティレベルも最大に設定してあるし！","ENG":"And why is the security level set to maximum, of all things?","TWN":"而且保管所的安全等級為什麼還設到最高啊？"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 무슨 마스터키야? 왜 공인 카운터가 일일이 문을 따줘야 하냐고……!","JPN":"私はマスターキーじゃないのよ！　公認カウンターがいちいち鍵を開けてやらないといけないなんてあり得る……！？","ENG":"What do I look like, a master key? Why does a Grade S Counter have to manually open every door?!","TWN":"我是萬用鑰匙嗎？為什麼要讓認證制裁者一個個去開門啊……！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그야, 이터니움은 한 장소에 대량으로 보관할 수 없으니까요.","JPN":"大量のエタニウムを1か所に保管することはできませんからね。","ENG":"Because Eternium can't be stockpiled in large quantities in a single location.","TWN":"那是因為永恆之金不能大量集中保管在同一個地點。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"각 지구마다 이터니움 소비량이 다르니, 매뉴얼적으로는 손색없는 정책입니다.","JPN":"地区によってエタニウム消費量は異なりますし、マニュアル的には立派な政策です。","ENG":"Each district has different Eternium consumption needs, so procedurally speaking, it's a sound policy.","TWN":"各區域的消耗量不同，從手冊角度來看，這個政策毫無缺點。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"조디악 나이츠가 주요 거점을 방어하는 동안, 우리는 이터니움을 확보해야 해요.","JPN":"ゾディアックナイツが主要拠点を防衛している間、私たちはエタニウムを確保しなければ。","ENG":"While the Zodiac Knights defend the major strongpoints, we need to secure the Eternium.","TWN":"在十二宮騎士團防守主要據點的同時，我們必須確保永恆之金。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"선로전환기를 가동시킬 양을 확보하기 위해서는 두 곳의 보관소를 더 들려야 합니다.","JPN":"線路転換器を稼働させるだけの量を集めるためには、あと2か所の保管所に寄る必要があります。","ENG":"To gather enough to operate the Track Switcher, we'll need to stop by two more storerooms.","TWN":"為了取得足以啟動線路轉換器的數量，還得再前往兩座保管所。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"우씨, 그 훌륭하신 매뉴얼이 우리 발목을 잡고 있잖아!","JPN":"もう、その立派なマニュアルが今は足を引っ張ってるんじゃない！","ENG":"Tch, that wonderful manual is what's tripping us up right now!","TWN":"哇嗚，那套了不起的手冊在扯我們後腿吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"귀찮아 죽겠네, 진짜!","JPN":"本当に面倒くさいわね！","ENG":"What a pain in the butt, seriously!","TWN":"煩死了，真是的！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이쪽이야, 후딱 끝내 버리자고.","JPN":"こっちよ、さっさと終わらせましょう。","ENG":"This way. Let's get it over with quickly.","TWN":"這邊啦，趕快結束吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시스템 권한을 확인 중.</color>","JPN":"<color=#ffd34c>システム権限を確認中。</color>","ENG":"<color=#ffd34c>Verifying system authorization.</color>","TWN":"<color=#ffd34c>系統權限確認中</color>"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>확인 완료. E-3 보관 구역 도어를 개방합니다.</color>","JPN":"<color=#ffd34c>確認完了。E-3保管区域のドアを開放します。</color>","ENG":"<color=#ffd34c>Verification complete. Opening E-3 storage sector door.</color>","TWN":"<color=#ffd34c>確認完成，開啟E-3保管區大門。</color>"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도어 개방 완료.</color>","JPN":"<color=#ffd34c>ドア開放完了。</color>","ENG":"<color=#ffd34c>Door opened.</color>","TWN":"<color=#ffd34c>門已開啟。</color>"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"세상에…! 대체 이게 다 얼마야……?","JPN":"わあ……！　すごい量……！","ENG":"Whoa...! Just how much is all this worth...?","TWN":"天啊……！這些到底有多少啊……？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 정도 비축량이면 평생 먹고 살 수 있겠는데……?","JPN":"この量なら一生働かなくてもいいんじゃ……？","ENG":"With a stockpile like this, you could live comfortably for the rest of your life...","TWN":"這種儲備量夠一輩子不愁吃穿了吧……？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하핫! 먹고 살기만 하겠어? 평생 떵떵거리면서 살 수 있다고, 수녀님?","JPN":"ははっ！　働かなくていいどころか、一生贅沢三昧できるわよ、シスター？","ENG":"Haha! Just comfortably? You could live like royalty forever, Sister.","TWN":"哈哈，只是不愁吃穿而已嗎？可以一輩子過著奢華的生活喔，修女？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"……두 사람, 혹시나 빼돌릴 생각은 그만두는 게 좋을 겁니다.","JPN":"……二人とも、着服するつもりならやめたほうがいいですよ。","ENG":"...You two would be wise to abandon any thoughts of sneaking them away.","TWN":"……你們兩個，最好別動歪腦筋。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"모든 작전 상황은 철저하게 통제되어 있습니다.","JPN":"すべての作戦状況は徹底的に統制されています。","ENG":"All operational conditions are under strict supervision.","TWN":"所有作戰狀況都受到嚴密控管。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"결정적인 순간에 이터니움 한 줌이 모자라서, 일을 그르칠 수는 없으니까요.","JPN":"決定的瞬間に一握りのエタニウムが不足して、すべてを台無しにするわけにはいきませんから。","ENG":"We can't afford to botch everything because we're short even a handful of Eternium at the critical moment.","TWN":"不能在關鍵時刻少了任何一點永恆之金，導致任務失敗。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"쯧, 나도 알고 있거든?","JPN":"ちっ、言われなくてもわかってるよ。","ENG":"Tsk. I know that already, okay?","TWN":"嘖，我也知道啦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼, 전부 수송차량으로 옮기면 되는 거지?","JPN":"じゃあ、これを全部輸送車両に運べばいいんだね？","ENG":"So we just load everything onto the transport vehicles, right?","TWN":"那麼把這些都搬上運輸車就行了吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그 전에…….","JPN":"その前に……","ENG":"Before that...","TWN":"在那之前……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_SHADOW","text":{"KOREA":"이 세계의 모든 재보는 모두 왕께서 내리신 보물이니…….","JPN":"この世界のすべての財宝は王から授かりし宝……","ENG":"All the treasures of this world are gifts bestowed by the queen...","TWN":"這世上所有的財寶，皆是王賜予的寶物……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_SHADOW","text":{"KOREA":"미물들은 머리를 조아리고, 무릎을 꿇어 그분의 뜻을 찬미하라.","JPN":"微物どもは頭を垂れ、跪き、あの方の思し召しを賛美せよ。","ENG":"Lowly creatures, bow your heads and bend your knees, and praise her will.","TWN":"渺小之物應屈膝叩首，讚頌祂的意志。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_SHADOW","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"먼저, 사소한 민사 분쟁부터 해결해야겠군요.","JPN":"つまらない民事紛争の解決が先のようです。","ENG":"First, it seems we need to settle a trivial civil dispute.","TWN":"看來得先解決一些小小的民事糾紛呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"}]`);export{e as default};